require "property.BaseProperty"

StealProperty = class("StealProperty", BaseProperty)

function StealProperty:onPlayerUsed(player, target, damage)
    if player == nil or target == nil then
        return
    end
    local inv = target:getInventory()
    local index = inv:getCurrentItemIndex()
    local info = inv:getItemStackInfo(index)
    if info.id <= 0 and info.id >= 10000 then
        return
    end
    if not inv:isCanAddItem(info.id, info.meta, info.num) then
        return
    end
    if not player:getInventory():isCanAddItem(info.id, info.meta, info.num) then
        return
    end
    if info.id == Define.HotPotato then
        player:becomeTntPlayer({ id = info.id, meta = 0 })
        target:becomeNormalPlayer()
        return
    end
    target:removeCurItem(info.num)
    player:addItem(info.id, info.num, info.meta)
end

return StealProperty